import anthropic, json, hashlib

client = anthropic.Anthropic()

SUBMISSION_PACKAGE_TOOL = {
    "name": "create_review_submission",
    "description": "Prepare an ensemble review submission package for a prompt or tool change",
    "input_schema": {
        "type": "object",
        "required": ["change_id", "change_type", "diff_summary",
                     "new_prompt_hash", "spec_items_addressed",
                     "eval_before", "eval_after", "reviewer_assignments"],
        "properties": {
            "change_id": {"type": "string"},
            "change_type": {"enum": ["prompt_minor", "prompt_moderate", "tool_schema", "both"]},
            "diff_summary": {
                "type": "string",
                "description": "Plain-English description of what changed and why"
            },
            "new_prompt_hash": {"type": "string"},
            "spec_items_addressed": {
                "type": "array",
                "items": {"type": "string"}
            },
            "eval_before": {
                "type": "object",
                "properties": {
                    "total": {"type": "integer"},
                    "passed": {"type": "integer"},
                    "must_not_do_violations": {"type": "integer"}
                }
            },
            "eval_after": {
                "type": "object",
                "properties": {
                    "total": {"type": "integer"},
                    "passed": {"type": "integer"},
                    "must_not_do_violations": {"type": "integer"}
                }
            },
            "reviewer_assignments": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "reviewer": {"type": "string"},
                        "dimension": {
                            "enum": ["spec_alignment", "eval_coverage",
                                     "safety_regression", "operational_impact"]
                        }
                    }
                }
            }
        }
    }
}

def create_review_submission(change_id, old_prompt, new_prompt,
                              eval_before, eval_after, spec_items, team):
    new_hash = hashlib.sha256(new_prompt.encode()).hexdigest()[:8]

    # Simple diff summary
    old_lines = set(old_prompt.split("\n"))
    new_lines = set(new_prompt.split("\n"))
    added = new_lines - old_lines
    removed = old_lines - new_lines

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[SUBMISSION_PACKAGE_TOOL],
        tool_choice={"type": "tool", "name": "create_review_submission"},
        messages=[{
            "role": "user",
            "content": (
                f"Create an ensemble review submission for change {change_id}.\n\n"
                f"Added lines: {list(added)[:5]}\n"
                f"Removed lines: {list(removed)[:5]}\n"
                f"New hash: {new_hash}\n"
                f"Spec items addressed: {spec_items}\n"
                f"Eval before: {json.dumps(eval_before)}\n"
                f"Eval after: {json.dumps(eval_after)}\n"
                f"Available reviewers: {team}\n\n"
                "Assign each reviewer one of the four dimensions. "
                "If fewer than 4 reviewers, the author takes operational_impact. "
                "change_type: prompt_minor if only wording changed, prompt_moderate if logic changed, "
                "tool_schema if any schema field changed."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

REVIEWER_WORKSHEET_TOOL = {
    "name": "complete_reviewer_worksheet",
    "description": "Complete a reviewer worksheet for one dimension of an ensemble review",
    "input_schema": {
        "type": "object",
        "required": ["dimension", "findings", "questions", "vote", "vote_rationale"],
        "properties": {
            "dimension": {
                "enum": ["spec_alignment", "eval_coverage",
                         "safety_regression", "operational_impact"]
            },
            "findings": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["severity", "description"],
                    "properties": {
                        "severity": {"enum": ["info", "concern", "block"]},
                        "description": {"type": "string"}
                    }
                }
            },
            "questions": {
                "type": "array",
                "description": "Questions to raise during the structured reveal",
                "items": {"type": "string"}
            },
            "vote": {"enum": ["APPROVE", "APPROVE_WITH_NOTES", "BLOCK"]},
            "vote_rationale": {"type": "string"}
        }
    }
}

def complete_reviewer_worksheet(dimension, submission_package, behaviour_spec):
    dimension_prompts = {
        "spec_alignment": (
            "Check: does the diff implement a spec item or fix a spec violation? "
            "Check: does any removed line implement a must-do item that would now be unimplemented? "
            "Check: does any added line contradict a must-not-do item? "
            "BLOCK if: any must-not-do item is weakened."
        ),
        "eval_coverage": (
            "Check: are new eval cases included that cover the changed behaviour? "
            "Check: does eval_after have higher pass rate than eval_before? "
            "Check: are there must-do items affected by this change with no eval case? "
            "BLOCK if: eval regressed or the changed behaviour has zero eval coverage."
        ),
        "safety_regression": (
            "Check: does any added instruction open a new misuse vector? "
            "Check: does any removed constraint remove a safety control? "
            "Check: does the change affect how the model handles sensitive domains? "
            "BLOCK if: any safety constraint is removed or weakened."
        ),
        "operational_impact": (
            "Check: does the prompt length change significantly (>10%)? "
            "Check: does the tool schema change in a backward-incompatible way? "
            "Check: could the change cause latency increases on edge inputs? "
            "BLOCK if: token budget now exceeds model limits, or schema change breaks existing callers."
        )
    }

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[REVIEWER_WORKSHEET_TOOL],
        tool_choice={"type": "tool", "name": "complete_reviewer_worksheet"},
        messages=[{
            "role": "user",
            "content": (
                f"Complete a reviewer worksheet for the {dimension} dimension.\n\n"
                f"Submission package:\n{json.dumps(submission_package, indent=2)}\n\n"
                f"Behaviour spec:\n{json.dumps(behaviour_spec, indent=2)}\n\n"
                f"Your review criteria:\n{dimension_prompts[dimension]}\n\n"
                "APPROVE if no concerns or only info-level findings. "
                "APPROVE_WITH_NOTES if concerns that should be addressed but are not blocking. "
                "BLOCK if any block-severity finding."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

ENSEMBLE_DECISION_TOOL = {
    "name": "record_ensemble_decision",
    "description": "Record the final decision from an ensemble review session",
    "input_schema": {
        "type": "object",
        "required": ["change_id", "decision", "blocking_findings",
                     "notes_for_revision", "reviewer_votes"],
        "properties": {
            "change_id": {"type": "string"},
            "decision": {"enum": ["APPROVED", "APPROVED_WITH_NOTES", "BLOCKED"]},
            "blocking_findings": {
                "type": "array",
                "description": "Findings that must be resolved before the change can merge",
                "items": {"type": "string"}
            },
            "notes_for_revision": {
                "type": "array",
                "description": "Non-blocking findings the author should address",
                "items": {"type": "string"}
            },
            "reviewer_votes": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "reviewer": {"type": "string"},
                        "dimension": {"type": "string"},
                        "vote": {"enum": ["APPROVE", "APPROVE_WITH_NOTES", "BLOCK"]}
                    }
                }
            }
        }
    }
}

def record_ensemble_decision(change_id, reviewer_worksheets):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[ENSEMBLE_DECISION_TOOL],
        tool_choice={"type": "tool", "name": "record_ensemble_decision"},
        messages=[{
            "role": "user",
            "content": (
                f"Record the ensemble review decision for change {change_id}.\n\n"
                f"Reviewer worksheets:\n{json.dumps(reviewer_worksheets, indent=2)}\n\n"
                "Decision rules:\n"
                "- BLOCKED if any reviewer voted BLOCK\n"
                "- APPROVED_WITH_NOTES if any reviewer voted APPROVE_WITH_NOTES and none BLOCK\n"
                "- APPROVED if all reviewers voted APPROVE\n"
                "blocking_findings = all block-severity findings across all worksheets."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
